-- Acts 11: Peter Defends the Gentile Mission and the Church at Antioch Is Born

-- 1. Chapter metadata
INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 11,
  'Acts 11 consolidates the Gentile breakthrough of chapter 10 through two strategic developments. First, Peter''s apostolic conduct is challenged by "they of the circumcision" in Jerusalem, who protest not the preaching of the gospel to Gentiles but Peter''s eating with them. Peter recounts the vision, the Spirit''s direction, the arrival of the messengers, the six witnessing brethren, and above all the sovereign descent of the Spirit on Cornelius''s household — a Pentecost he neither asked for nor controlled. His defense is irresistibly simple: if God has given them the same gift he gave us, "who was I, that I could withstand God?" The Jerusalem church, remarkable in its teachability, glorifies God with the epoch-making conclusion: "Then hath God also to the Gentiles granted repentance unto life." Second, Luke traces a parallel, unforeseen gospel advance. The diaspora from Stephen''s persecution had reached as far as Phenice, Cyprus, and Antioch, preaching to Jews only. But some Cypriots and Cyrenians at Antioch begin to preach the Lord Jesus to the Greeks, and "the hand of the Lord was with them." When the Jerusalem church sends Barnabas to investigate, he sees "the grace of God" and rejoices, exhorts the converts to steadfastness, and — in an act that will shape the worldwide mission — travels to Tarsus to fetch Saul. For a whole year Barnabas and Saul teach the Antioch church, and here the believers are first called "Christians" — a name probably coined as a term of derision by outsiders but divinely appropriated as the enduring badge of the new community. Finally, Agabus foretells a great famine (fulfilled under Claudius, c. AD 45-47), and the Antioch church — freshly Gentile and newly named — sends relief back to Jerusalem "by the hands of Barnabas and Saul," demonstrating mature, reciprocal koinonia between Jewish and Gentile Christians.',
  'God Grants Repentance Unto Life to the Gentiles; the Church at Antioch Is Born',
  'Χριστιανούς',
  'Christians (lit. ones of Christ, Christ-followers)',
  '["Peter defends the Gentile mission before the Jerusalem church (vv.1-18)", "The gospel reaches Antioch and Greeks believe (vv.19-21)", "Barnabas at Antioch; he fetches Saul from Tarsus (vv.22-26)", "Agabus prophesies famine; relief sent to Jerusalem (vv.27-30)"]'::jsonb
FROM books b WHERE b.name = 'Acts'
ON CONFLICT (book_id, chapter_number) DO UPDATE SET
  overview = EXCLUDED.overview,
  theme = EXCLUDED.theme,
  key_word_original = EXCLUDED.key_word_original,
  key_word_meaning = EXCLUDED.key_word_meaning,
  outline = EXCLUDED.outline;

-- 2. Verses
INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'And the apostles and brethren that were in Judaea heard that the Gentiles had also received the word of God.',
   'Ἤκουσαν δὲ οἱ ἀπόστολοι καὶ οἱ ἀδελφοὶ οἱ ὄντες κατὰ τὴν Ἰουδαίαν ὅτι καὶ τὰ ἔθνη ἐδέξαντο τὸν λόγον τοῦ θεοῦ.',
   'Ēkousan de hoi apostoloi kai hoi adelphoi hoi ontes kata tēn Ioudaian hoti kai ta ethnē edexanto ton logon tou theou.',
   'News of Caesarea reaches Judean congregations quickly. "Edexanto ton logon tou theou" ("received the word of God") is Luke''s technical phrase for genuine conversion (cf. 8:14; 17:11). The epoch-making fact is framed simply: the nations have received the gospel.',
   'Authentic conversion consists in receiving the word of God. The test of every alleged spiritual movement is whether Scripture has been welcomed as the authoritative voice of God over one''s life.'),
  (2, 'And when Peter was come up to Jerusalem, they that were of the circumcision contended with him,',
   'Ὅτε δὲ ἀνέβη Πέτρος εἰς Ἰερουσαλήμ, διεκρίνοντο πρὸς αὐτὸν οἱ ἐκ περιτομῆς',
   'Hote de anebē Petros eis Ierousalēm, diekrinonto pros auton hoi ek peritomēs',
   '"Hoi ek peritomēs" ("those of the circumcision") — Jewish Christians zealous for Torah observance. "Diekrinonto" ("contended, disputed") is plural and aggressive. Even apostolic authority does not exempt Peter from congregational scrutiny in the early church.',
   'Apostolic conduct was subject to congregational accountability. Early Christianity is a fellowship of mutual scrutiny, not a hierarchy above question; Peter does not claim immunity but explains his actions.'),
  (3, 'Saying, Thou wentest in to men uncircumcised, and didst eat with them.',
   'λέγοντες ὅτι εἰσῆλθες πρὸς ἄνδρας ἀκροβυστίαν ἔχοντας καὶ συνέφαγες αὐτοῖς.',
   'Legontes hoti eisēlthes pros andras akrobystian echontas kai synephages autois.',
   '"Synephages" ("didst eat with") is the specific grievance, not evangelism per se. Table fellowship with Gentiles breached the halakhic boundary that separated Israel; this is the very issue Galatians 2:11-14 will later revisit.',
   'Table fellowship between Jew and Gentile believers was the concrete frontier where gospel inclusion had to be worked out. The issue was not merely doctrinal but practical — who sits at whose table publicly embodies who belongs to whom.'),
  (4, 'But Peter rehearsed the matter from the beginning, and expounded it by order unto them, saying,',
   'ἀρξάμενος δὲ Πέτρος ἐξετίθετο αὐτοῖς καθεξῆς λέγων·',
   'Arxamenos de Petros exetitheto autois kathexēs legōn;',
   '"Kathexēs" ("in order") is a favorite Lukan word for orderly narration (Luke 1:3). Peter defends by narration, not argument: he recounts what God did, and the narrative is its own theology.',
   'Divine acts, rightly recounted, carry their own argument. The most powerful defense of God''s surprising work is faithful narrative of what was seen and heard.'),
  (5, 'I was in the city of Joppa praying: and in a trance I saw a vision, A certain vessel descend, as it had been a great sheet, let down from heaven by four corners; and it came even to me:',
   'ἐγὼ ἤμην ἐν πόλει Ἰόππῃ προσευχόμενος, καὶ εἶδον ἐν ἐκστάσει ὅραμα, καταβαῖνον σκεῦός τι ὡς ὀθόνην μεγάλην τέσσαρσιν ἀρχαῖς καθιεμένην ἐκ τοῦ οὐρανοῦ, καὶ ἦλθεν ἄχρι ἐμοῦ·',
   'Egō ēmēn en polei Ioppē proseuchomenos, kai eidon en ekstasei horama, katabainon skeuos ti hōs othonēn megalēn tessarsin archais kathiemenēn ek tou ouranou, kai ēlthen achri emou;',
   'Peter retells chapter 10 compactly. "Achri emou" ("as far as me") personalizes the divine address; the sheet came right to his feet.',
   'Divine revelations come to particular persons in particular places. The universal implications of God''s acts are always delivered through specific personal encounters Peter retells his own encounter with God to explain a doctrine that will reshape the church.'),
  (6, 'Upon the which when I had fastened mine eyes, I considered, and saw fourfooted beasts of the earth, and wild beasts, and creeping things, and fowls of the air.',
   'εἰς ἣν ἀτενίσας κατενόουν καὶ εἶδον τὰ τετράποδα τῆς γῆς καὶ τὰ θηρία καὶ τὰ ἑρπετὰ καὶ τὰ πετεινὰ τοῦ οὐρανοῦ.',
   'Eis hēn atenisas katenooun kai eidon ta tetrapoda tēs gēs kai ta thēria kai ta herpeta kai ta peteina tou ouranou.',
   '"Atenisas katenooun" ("fastening my gaze, I was observing") — Peter is careful to emphasize the deliberate, conscious inspection. This was no dream or hallucination; he inspected the vision.',
   'True spiritual perception requires close attention. Mystery is not the enemy of observation; what God shows is meant to be carefully examined and understood.'),
  (7, 'And I heard a voice saying unto me, Arise, Peter; slay and eat.',
   'ἤκουσα δὲ καὶ φωνῆς λεγούσης μοι· ἀναστάς, Πέτρε, θῦσον καὶ φάγε.',
   'Ēkousa de kai phōnēs legousēs moi; anastas, Petre, thyson kai phage.',
   'The repetition of the command strengthens the theological point. In narration, Peter is inviting the Jerusalem brethren to hear what he heard — to let the voice of God overwrite their received tradition.',
   'Divine speech is the supreme court of theological revision. No ancestral pattern, however venerable, outranks a clear command of God newly spoken.'),
  (8, 'But I said, Not so, Lord: for nothing common or unclean hath at any time entered into my mouth.',
   'εἶπον δέ· μηδαμῶς, κύριε, ὅτι κοινὸν ἢ ἀκάθαρτον οὐδέποτε εἰσῆλθεν εἰς τὸ στόμα μου.',
   'Eipon de; mēdamōs, kyrie, hoti koinon ē akatharton oudepote eisēlthen eis to stoma mou.',
   'Peter highlights his own initial resistance — a brilliant rhetorical move. If he, a lifelong Torah-observant Jew, resisted but was corrected by God, the Jerusalem hearers can follow his example.',
   'Confession of one''s prior resistance is a powerful tool of persuasion. The preacher who admits his own slowness to grasp divine revelation disarms the objections of those who still resist.'),
  (9, 'But the voice answered me again from heaven, What God hath cleansed, that call not thou common.',
   'ἀπεκρίθη δὲ φωνὴ ἐκ δευτέρου ἐκ τοῦ οὐρανοῦ· ἃ ὁ θεὸς ἐκαθάρισεν, σὺ μὴ κοίνου.',
   'Apekrithē de phōnē ek deuterou ek tou ouranou; ha ho theos ekatharisen, sy mē koinou.',
   'The decisive theological sentence is repeated verbatim from 10:15 — a refrain that Peter, and now Jerusalem, cannot unhear. Divine cleansing defines what is clean; human categories must yield.',
   'Divine cleansing redefines all prior categories of clean and unclean. The authority to call something common resides with the Creator alone, and where he has cleansed, his people have no veto.'),
  (10, 'And this was done three times: and all were drawn up again into heaven.',
   'τοῦτο δὲ ἐγένετο ἐπὶ τρίς, καὶ ἀνεσπάσθη πάλιν ἅπαντα εἰς τὸν οὐρανόν.',
   'Touto de egeneto epi tris, kai anespasthē palin hapanta eis ton ouranon.',
   'The threefold sign now functions as authenticating witness to the Jerusalem court. In Mosaic law, "in the mouth of two or three witnesses shall every word be established" (Deut 19:15); three heavenly iterations exceed that evidentiary threshold.',
   'Divine repetition authenticates revelation for a skeptical audience. The threefold sign that overcame Peter''s resistance now becomes the legal warrant his hearers must heed.'),
  (11, 'And, behold, immediately there were three men already come unto the house where I was, sent from Caesarea unto me.',
   'καὶ ἰδοὺ ἐξαυτῆς τρεῖς ἄνδρες ἐπέστησαν ἐπὶ τὴν οἰκίαν ἐν ᾗ ἤμην, ἀπεσταλμένοι ἀπὸ Καισαρείας πρός με.',
   'Kai idou exautēs treis andres epestēsan epi tēn oikian en hē ēmēn, apestalmenoi apo Kaisareias pros me.',
   'Three men match the three heavenly iterations — Luke''s numeric symmetry underscores providential orchestration. The messengers arrive at the precise moment the vision ends.',
   'God coordinates his revelations with his providential arrivals. The word he speaks inwardly is confirmed by what appears at the door; the seer learns the meaning of the sign by its exact correspondence to the circumstance.'),
  (12, 'And the Spirit bade me go with them, nothing doubting. Moreover these six brethren accompanied me, and we entered into the man''s house:',
   'εἶπεν δὲ τὸ πνεῦμά μοι συνελθεῖν αὐτοῖς μηδὲν διακρίναντα. ἦλθον δὲ σὺν ἐμοὶ καὶ οἱ ἓξ ἀδελφοὶ οὗτοι, καὶ εἰσήλθομεν εἰς τὸν οἶκον τοῦ ἀνδρός.',
   'Eipen de to pneuma moi synelthein autois mēden diakrinanta. Ēlthon de syn emoi kai hoi hex adelphoi houtoi, kai eisēlthomen eis ton oikon tou andros.',
   '"Hoi hex adelphoi houtoi" ("these six brethren") — Peter has brought his Joppa witnesses with him to Jerusalem. Seven witnesses total (Peter plus six) make the testimony unassailable under Jewish legal standards.',
   'God provides his servants with corroborating witnesses at the hour of their greatest need. Disputed decisions in the church are best settled by a plurality of qualified eyewitnesses acting together.'),
  (13, 'And he shewed us how he had seen an angel in his house, which stood and said unto him, Send men to Joppa, and call for Simon, whose surname is Peter;',
   'ἀπήγγειλεν δὲ ἡμῖν πῶς εἶδεν τὸν ἄγγελον ἐν τῷ οἴκῳ αὐτοῦ σταθέντα καὶ εἰπόντα· ἀπόστειλον εἰς Ἰόππην καὶ μετάπεμψαι Σίμωνα τὸν ἐπικαλούμενον Πέτρον,',
   'Apēngeilen de hēmin pōs eiden ton angelon en tō oikō autou stathenta kai eiponta; aposteilon eis Ioppēn kai metapempsai Simōna ton epikaloumenon Petron,',
   'Peter piles on the evidence: the Gentile side of the story has its own angelic visitation. The independence of the two revelations — neither party could have fabricated the convergence — is the strongest proof of divine orchestration.',
   'Independent, converging divine witness is irrefutable. When two parties unknown to each other are given coordinated revelations, the work is unmistakably God''s.'),
  (14, 'Who shall tell thee words, whereby thou and all thy house shall be saved.',
   'ὃς λαλήσει ῥήματα πρὸς σέ, ἐν οἷς σωθήσῃ σὺ καὶ πᾶς ὁ οἶκός σου.',
   'Hos lalēsei rhēmata pros se, en hois sōthēsē sy kai pas ho oikos sou.',
   '"Rhēmata… en hois sōthēsē" ("words in which you will be saved") — salvation comes through spoken words, not private intuition. The household dimension ("pas ho oikos") is pronounced: salvation spreads by the word through relational units.',
   'Salvation requires hearing the specific words of the gospel. No amount of piety or yearning saves apart from the proclaimed message of Christ; this is why preaching is irreplaceable, and why God sends preachers to seekers.'),
  (15, 'And as I began to speak, the Holy Ghost fell on them, as on us at the beginning.',
   'ἐν δὲ τῷ ἄρξασθαί με λαλεῖν ἐπέπεσεν τὸ πνεῦμα τὸ ἅγιον ἐπ’ αὐτοὺς ὥσπερ καὶ ἐφ’ ἡμᾶς ἐν ἀρχῇ.',
   'En de tō arxasthai me lalein epepesen to pneuma to hagion ep'' autous hōsper kai eph'' hēmas en archē.',
   '"En archē" ("in the beginning") Peter refers to Pentecost; "hōsper" ("just as") binds the two events theologically. The Gentile Pentecost is identified with the Jewish Pentecost by the very Spirit who authors both.',
   'Gentile and Jewish believers share the same Spirit, the same gift, and the same church. The Spirit does not dispense subsidiary or lesser blessings upon the Gentiles; he pours out the identical Pentecost.'),
  (16, 'Then remembered I the word of the Lord, how that he said, John indeed baptized with water; but ye shall be baptized with the Holy Ghost.',
   'ἐμνήσθην δὲ τοῦ ῥήματος τοῦ κυρίου ὡς ἔλεγεν· Ἰωάννης μὲν ἐβάπτισεν ὕδατι, ὑμεῖς δὲ βαπτισθήσεσθε ἐν πνεύματι ἁγίῳ.',
   'Emnēsthēn de tou rhēmatos tou kyriou hōs elegen; Iōannēs men ebaptisen hydati, hymeis de baptisthēsesthe en pneumati hagiō.',
   'Peter remembers Jesus'' words (Acts 1:5). The phenomenon at Cornelius''s house is identified as the "baptism with the Holy Ghost." This is the interpretive key: the divine event at Caesarea is the Lord''s own fulfillment of his promise.',
   'The words of Christ are the interpretive grid for all subsequent work of the Spirit. When a new divine act occurs, the faithful ask: where did the Lord say he would do this?'),
  (17, 'Forasmuch then as God gave them the like gift as he did unto us, who believed on the Lord Jesus Christ; what was I, that I could withstand God?',
   'εἰ οὖν τὴν ἴσην δωρεὰν ἔδωκεν αὐτοῖς ὁ θεὸς ὡς καὶ ἡμῖν πιστεύσασιν ἐπὶ τὸν κύριον Ἰησοῦν Χριστόν, ἐγὼ τίς ἤμην δυνατὸς κωλῦσαι τὸν θεόν;',
   'Ei oun tēn isēn dōrean edōken autois ho theos hōs kai hēmin pisteusasin epi ton kyrion Iēsoun Christon, egō tis ēmēn dynatos kōlysai ton theon?',
   '"Tēn isēn dōrean" ("the equal gift") is categorical: the gift given to the Gentiles is identical to what Jews received. "Tis ēmēn dynatos kōlysai ton theon?" ("who was I to withstand God?") is the inescapable conclusion; the argument cannot be answered.',
   'To oppose the Gentile inclusion is to oppose God himself. The distinction between Jew and Gentile in saving grace has been erased by divine fiat, and no ecclesial authority may re-erect it.'),
  (18, 'When they heard these things, they held their peace, and glorified God, saying, Then hath God also to the Gentiles granted repentance unto life.',
   'ἀκούσαντες δὲ ταῦτα ἡσύχασαν καὶ ἐδόξασαν τὸν θεὸν λέγοντες· ἄρα καὶ τοῖς ἔθνεσιν ὁ θεὸς τὴν μετάνοιαν εἰς ζωὴν ἔδωκεν.',
   'Akousantes de tauta hēsychasan kai edoxasan ton theon legontes; ara kai tois ethnesin ho theos tēn metanoian eis zōēn edōken.',
   'The Jerusalem church''s response is remarkable: "hēsychasan" ("they became silent") — the disputation ceased. Then they glorified God. Their theological conclusion — "repentance unto life" for Gentiles — is the first programmatic affirmation of Gentile inclusion by the apostolic church.',
   'True teachability falls silent before the clear working of God and then bursts into praise. The Jerusalem church models a posture every generation of believers must learn: to revise inherited categories when heaven clarifies its own purpose.'),
  (19, 'Now they which were scattered abroad upon the persecution that arose about Stephen travelled as far as Phenice, and Cyprus, and Antioch, preaching the word to none but unto the Jews only.',
   'Οἱ μὲν οὖν διασπαρέντες ἀπὸ τῆς θλίψεως τῆς γενομένης ἐπὶ Στεφάνῳ διῆλθον ἕως Φοινίκης καὶ Κύπρου καὶ Ἀντιοχείας, μηδενὶ λαλοῦντες τὸν λόγον εἰ μὴ μόνον Ἰουδαίοις.',
   'Hoi men oun diasparentes apo tēs thlipseōs tēs genomenēs epi Stephanō diēlthon heōs Phoinikēs kai Kyprou kai Antiocheias, mēdeni lalountes ton logon ei mē monon Ioudaiois.',
   'Luke resumes the narrative thread from 8:1, now expanding it geographically. Phoenicia (modern Lebanon coast), Cyprus, and Antioch (Syrian Antioch — "queen of the East," the third-largest city of the Roman Empire at ~500,000) become the new fronts. The Stephen-refugees are initially Jewish-only in their preaching.',
   'God uses persecution to scatter the gospel into unforeseen territories. What the persecutors intended to silence, the Lord amplifies; ordinary displaced believers become the first missionaries to Asia, Africa, and Syria.'),
  (20, 'And some of them were men of Cyprus and Cyrene, which, when they were come to Antioch, spake unto the Grecians, preaching the Lord Jesus.',
   'ἦσαν δέ τινες ἐξ αὐτῶν ἄνδρες Κύπριοι καὶ Κυρηναῖοι, οἵτινες ἐλθόντες εἰς Ἀντιόχειαν ἐλάλουν καὶ πρὸς τοὺς Ἑλληνιστάς, εὐαγγελιζόμενοι τὸν κύριον Ἰησοῦν.',
   'Ēsan de tines ex autōn andres Kyprioi kai Kyrēnaioi, hoitines elthontes eis Antiocheian elaloun kai pros tous Hellēnistas, euangelizomenoi ton kyrion Iēsoun.',
   'The manuscripts divide between "Hellēnistas" (Greek-speaking Jews) and "Hellēnas" (Greeks, i.e. Gentiles); the narrative context strongly suggests Gentiles are meant. These unnamed Cypriot and Cyrenian believers — not apostles, not named leaders — take the momentous step of preaching to uncircumcised Gentiles.',
   'God often advances his mission through anonymous, ordinary disciples. The watershed transition at Antioch is led by unnamed brothers from Cyprus and Cyrene, proving that the kingdom does not wait upon official hierarchy.'),
  (21, 'And the hand of the Lord was with them: and a great number believed, and turned unto the Lord.',
   'καὶ ἦν χεὶρ κυρίου μετ’ αὐτῶν, πολύς τε ἀριθμὸς ὁ πιστεύσας ἐπέστρεψεν ἐπὶ τὸν κύριον.',
   'Kai ēn cheir kyriou met'' autōn, polys te arithmos ho pisteusas epestrepsen epi ton kyrion.',
   '"Cheir kyriou" ("hand of the Lord") is OT idiom for divine power at work (1 Kgs 18:46; Ezek 37:1). The missional initiative is authenticated by the same divine power that backed the original apostolic preaching.',
   'God owns the courageous step by visible empowerment. When his people risk obedience into unfamiliar territory, the hand of the Lord is with them, converting by the same divine power that drove the original Pentecost.'),
  (22, 'Then tidings of these things came unto the ears of the church which was in Jerusalem: and they sent forth Barnabas, that he should go as far as Antioch.',
   'ἠκούσθη δὲ ὁ λόγος εἰς τὰ ὦτα τῆς ἐκκλησίας τῆς οὔσης ἐν Ἰερουσαλὴμ περὶ αὐτῶν, καὶ ἐξαπέστειλαν Βαρναβᾶν ἕως Ἀντιοχείας.',
   'Ēkousthē de ho logos eis ta ōta tēs ekklēsias tēs ousēs en Ierousalēm peri autōn, kai exapesteilan Barnaban heōs Antiocheias.',
   'Barnabas is the inspired choice: a Levite of Cyprus (4:36), therefore a countryman of the Antioch pioneers; a man "full of the Holy Ghost and of faith" (v.24); and the one who had already vouched for Saul (9:27). Jerusalem''s oversight is pastoral, not controlling.',
   'Healthy church oversight walks alongside new works, not over them. Jerusalem sends a son of encouragement, not an inspector, to the new Gentile frontier — recognizing that new wine requires new, receptive wineskins.'),
  (23, 'Who, when he came, and had seen the grace of God, was glad, and exhorted them all, that with purpose of heart they would cleave unto the Lord.',
   'ὃς παραγενόμενος καὶ ἰδὼν τὴν χάριν τοῦ θεοῦ ἐχάρη, καὶ παρεκάλει πάντας τῇ προθέσει τῆς καρδίας προσμένειν τῷ κυρίῳ,',
   'Hos paragenomenos kai idōn tēn charin tou theou echarē, kai parekalei pantas tē prothesei tēs kardias prosmenein tō kyriō,',
   '"Idōn tēn charin tou theou" ("seeing the grace of God") — Barnabas recognizes authentic conversion by its visible fruit, not by ceremonial marks. His exhortation — "prothesei tēs kardias" ("with purpose of heart") — is not against Torah but for persevering attachment to Christ.',
   'Grace is visible where it is genuine; its presence can be recognized by spiritual discernment. The mature believer rejoices at the fruit of the Spirit wherever it grows, and exhorts new believers to resolute continuance in Christ.'),
  (24, 'For he was a good man, and full of the Holy Ghost and of faith: and much people was added unto the Lord.',
   'ὅτι ἦν ἀνὴρ ἀγαθὸς καὶ πλήρης πνεύματος ἁγίου καὶ πίστεως. καὶ προσετέθη ὄχλος ἱκανὸς τῷ κυρίῳ.',
   'Hoti ēn anēr agathos kai plērēs pneumatos hagiou kai pisteōs. Kai prosetethē ochlos hikanos tō kyriō.',
   '"Anēr agathos" ("a good man") — a rare accolade in Acts, granted also to Cornelius (10:22). Barnabas''s character is the prerequisite of his ministry fruitfulness; the church grows by him because he is himself being shaped by the Spirit.',
   'Character is the basis of effective ministry. Fullness of Holy Spirit and faith are not decorative qualifications but the substantive source of fruitful pastoral impact on new believers.'),
  (25, 'Then departed Barnabas to Tarsus, for to seek Saul:',
   'ἐξῆλθεν δὲ εἰς Ταρσὸν ἀναζητῆσαι Σαῦλον,',
   'Exēlthen de eis Tarson anazētēsai Saulon,',
   '"Anazētēsai" ("to search out, look up") — Saul had been in Tarsus for several years (c. AD 38-45), out of public ministry. Barnabas, discerning that the predominantly Gentile Antioch work requires Saul''s unique calling, travels to retrieve him. This is among the most consequential journeys in church history.',
   'God prepares specific servants in obscurity for specific works in the spotlight. The hidden years are not wasted years; they are formation time, and their fruit becomes visible only when the Lord appoints the hour of deployment.'),
  (26, 'And when he had found him, he brought him unto Antioch. And it came to pass, that a whole year they assembled themselves with the church, and taught much people. And the disciples were called Christians first in Antioch.',
   'καὶ εὑρὼν ἤγαγεν εἰς Ἀντιόχειαν. ἐγένετο δὲ αὐτοῖς καὶ ἐνιαυτὸν ὅλον συναχθῆναι ἐν τῇ ἐκκλησίᾳ καὶ διδάξαι ὄχλον ἱκανόν, χρηματίσαι τε πρώτως ἐν Ἀντιοχείᾳ τοὺς μαθητὰς Χριστιανούς.',
   'Kai heurōn ēgagen eis Antiocheian. Egeneto de autois kai eniauton holon synachthēnai en tē ekklēsia kai didaxai ochlon hikanon, chrēmatisai te prōtōs en Antiocheia tous mathētas Christianous.',
   '"Christianous" ("Christians") is formed on the Latinate pattern Herodianoi, Caesarianoi — "partisans of Christ." The name probably originated as a popular or official designation (Antioch was a city famous for sharp nicknames); Agrippa II uses it in 26:28, and 1 Peter 4:16 describes it as a name to suffer under. Luke presents it as providential: the multi-ethnic church needs a multi-ethnic name.',
   'The church''s enduring name is Christ-centered. Believers are not primarily Jews, Greeks, Romans, or moderns — they are "ones of Christ," and this identity transcends and relativizes every prior categorization.'),
  (27, 'And in these days came prophets from Jerusalem unto Antioch.',
   'Ἐν ταύταις δὲ ταῖς ἡμέραις κατῆλθον ἀπὸ Ἱεροσολύμων προφῆται εἰς Ἀντιόχειαν·',
   'En tautais de tais hēmerais katēlthon apo Hierosolymōn prophētai eis Antiocheian;',
   '"Prophētai" ("prophets") are a recognized order in the early church (13:1; 21:9-10; 1 Cor 12:28; Eph 4:11). Jerusalem sends its gifts to the daughter congregation; the traffic of ministry now flows in both directions.',
   'Spiritual gifts circulate between mother and daughter churches for mutual strengthening. No congregation is spiritually self-sufficient; each receives from and contributes to the wider body.'),
  (28, 'And there stood up one of them named Agabus, and signified by the Spirit that there should be great dearth throughout all the world: which came to pass in the days of Claudius Caesar.',
   'ἀναστὰς δὲ εἷς ἐξ αὐτῶν ὀνόματι Ἄγαβος ἐσήμανεν διὰ τοῦ πνεύματος λιμὸν μέγαν μέλλειν ἔσεσθαι ἐφ’ ὅλην τὴν οἰκουμένην· ἥτις ἐγένετο ἐπὶ Κλαυδίου.',
   'Anastas de heis ex autōn onomati Agabos esēmanen dia tou pneumatos limon megan mellein esesthai eph'' holēn tēn oikoumenēn; hētis egeneto epi Klaudiou.',
   'Agabus reappears in 21:10-11 foretelling Paul''s arrest. The famine under Claudius (AD 41-54) is attested by Josephus, Suetonius, and Tacitus — a series of crop failures affected the entire Mediterranean basin in the mid-40s, with Judea especially hard hit c. AD 45-47.',
   'The Holy Spirit grants predictive revelation that is verified by subsequent history. Biblical prophecy is not vague sentiment but specific foretelling corroborated by extra-biblical record; Christianity is a religion anchored in falsifiable history.'),
  (29, 'Then the disciples, every man according to his ability, determined to send relief unto the brethren which dwelt in Judaea:',
   'τῶν δὲ μαθητῶν καθὼς εὐπορεῖτό τις ὥρισαν ἕκαστος αὐτῶν εἰς διακονίαν πέμψαι τοῖς κατοικοῦσιν ἐν τῇ Ἰουδαίᾳ ἀδελφοῖς·',
   'Tōn de mathētōn kathōs euporeito tis hōrisan hekastos autōn eis diakonian pempsai tois katoikousin en tē Ioudaia adelphois;',
   '"Kathōs euporeito" ("according to his ability") establishes the principle of proportional giving (cf. 2 Cor 8:12). The young Gentile Antioch church gives to the older Jewish Jerusalem church — a reversal of expected flow that embodies the new covenant fellowship.',
   'Gospel fellowship is expressed in proportional, cross-cultural generosity. Christian giving is not flat equality but equitable proportion, each person contributing according to actual ability; and love crosses ethnic lines to sustain the saints.'),
  (30, 'Which also they did, and sent it to the elders by the hands of Barnabas and Saul.',
   'ὃ καὶ ἐποίησαν ἀποστείλαντες πρὸς τοὺς πρεσβυτέρους διὰ χειρὸς Βαρναβᾶ καὶ Σαύλου.',
   'Ho kai epoiēsan aposteilantes pros tous presbyterous dia cheiros Barnaba kai Saulou.',
   'First mention of "presbyterous" ("elders") in Acts for a Christian ordering of leadership, modeled on the Jewish synagogue. Barnabas and Saul, now partnered, make the first of several Jerusalem trips together — a relational bond that will be stressed in the first missionary journey.',
   'Gospel leadership is pluriform and plural: apostles, prophets, evangelists, elders. The church matures into an ordered structure of service, and the relief fund flows through trusted hands to responsible offices.')
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Acts' AND c.chapter_number = 11
ON CONFLICT (chapter_id, verse_number) DO UPDATE SET
  kjv_text = EXCLUDED.kjv_text,
  original_text = EXCLUDED.original_text,
  transliteration = EXCLUDED.transliteration,
  study_note = EXCLUDED.study_note,
  doctrinal_note = EXCLUDED.doctrinal_note;

-- 3. Word studies
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'ἐδέξαντο', 'edexanto', 'G1209', 'Received, welcomed. Luke''s technical verb for authentic reception of the gospel word.', 1),
  (2, 'διεκρίνοντο', 'diekrinonto', 'G1252', 'Disputed, contended. Middle-imperfect; an ongoing back-and-forth disputation, not a brief question.', 2),
  (3, 'ἀκροβυστίαν', 'akrobystian', 'G203', 'Uncircumcision. Physical mark distinguishing Gentiles from Jews under the old covenant.', 3),
  (3, 'συνέφαγες', 'synephages', 'G4906', 'Ate together with. The specific grievance—table fellowship, not evangelism, was the scandal.', 4),
  (4, 'καθεξῆς', 'kathexēs', 'G2517', 'In order, sequentially. Lukan term for orderly narration (cf. Luke 1:3).', 5),
  (5, 'ἐκστάσει', 'ekstasei', 'G1611', 'Trance, ecstasy. State of heightened spiritual reception.', 6),
  (12, 'διακρίναντα', 'diakrinanta', 'G1252', 'Hesitating, discriminating. Same verb as v.2; Spirit commands Peter not to do what his critics are doing.', 7),
  (14, 'ῥήματα', 'rhēmata', 'G4487', 'Words, utterances. Salvation is conveyed through specific spoken proclamation.', 8),
  (14, 'σωθήσῃ', 'sōthēsē', 'G4982', 'You will be saved. Future passive; saving act is divine, reception is human.', 9),
  (15, 'ἐπέπεσεν', 'epepesen', 'G1968', 'Fell upon. Sovereign descent of the Spirit, identical verb to Pentecost (10:44).', 10),
  (16, 'ἐμνήσθην', 'emnēsthēn', 'G3415', 'I remembered. Peter''s Spirit-aided recall of the Lord''s saying becomes hermeneutical key.', 11),
  (17, 'ἴσην δωρεὰν', 'isēn dōrean', 'G2470/G1431', 'Equal gift. The Spirit bestowed on Gentiles is categorically identical with that given to Jews.', 12),
  (17, 'κωλῦσαι', 'kōlysai', 'G2967', 'To hinder, prevent. The rhetorical point: no one can lawfully obstruct what God himself has done.', 13),
  (18, 'ἡσύχασαν', 'hēsychasan', 'G2270', 'Became silent, were quieted. Teachable response to divine evidence.', 14),
  (18, 'μετάνοιαν', 'metanoian', 'G3341', 'Repentance, change of mind. Fundamental response to the gospel; granted by God to Gentiles.', 15),
  (19, 'διασπαρέντες', 'diasparentes', 'G1289', 'Scattered. Persecution-driven diaspora; etymological root of ''diaspora.''', 16),
  (20, 'εὐαγγελιζόμενοι', 'euangelizomenoi', 'G2097', 'Preaching good news. Participle of continuous evangelistic activity.', 17),
  (21, 'χεὶρ κυρίου', 'cheir kyriou', 'G5495/G2962', 'Hand of the Lord. OT idiom for divine power at work (1 Kgs 18:46).', 18),
  (21, 'ἐπέστρεψεν', 'epestrepsen', 'G1994', 'Turned. Conversion language; reorientation of life toward the Lord.', 19),
  (23, 'χάριν', 'charin', 'G5485', 'Grace. The divine enabling power visibly operative among the Antioch believers.', 20),
  (23, 'προθέσει', 'prothesei', 'G4286', 'Purpose, resolve, determination. Settled intentional commitment, not mere feeling.', 21),
  (23, 'προσμένειν', 'prosmenein', 'G4357', 'To remain close to, abide by. Perseverance in attachment to Christ.', 22),
  (24, 'ἀγαθὸς', 'agathos', 'G18', 'Good, intrinsically excellent. Rare predicate of a person in Acts; Barnabas shares it with Cornelius.', 23),
  (25, 'ἀναζητῆσαι', 'anazētēsai', 'G327', 'To search out, look up carefully. Barnabas actively hunts Saul down in Tarsus.', 24),
  (26, 'Χριστιανούς', 'Christianous', 'G5546', 'Christians, partisans of Christ. First occurrence of the name that will define the movement.', 25),
  (26, 'χρηματίσαι', 'chrēmatisai', 'G5537', 'Called, named. Same verb used of divine revelation earlier; here used of public naming.', 26),
  (28, 'ἐσήμανεν', 'esēmanen', 'G4591', 'Signified, made known by sign. Prophetic verb often with symbolic revelation.', 27),
  (28, 'λιμὸν', 'limon', 'G3042', 'Famine, hunger. Great famine during Claudius (AD 41-54), attested by multiple secular sources.', 28),
  (28, 'οἰκουμένην', 'oikoumenēn', 'G3625', 'The inhabited world. Luke uses it of the Roman Empire; the famine was Mediterranean-wide.', 29),
  (29, 'εὐπορεῖτό', 'euporeito', 'G2141', 'Was prospering, had the means. Economic capacity varies; giving proportions accordingly.', 30),
  (29, 'διακονίαν', 'diakonian', 'G1248', 'Service, ministry, relief. The word for table-service becomes the word for diaconal aid.', 31),
  (30, 'πρεσβυτέρους', 'presbyterous', 'G4245', 'Elders. First mention of Christian elders; office inherited from synagogue leadership.', 32)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Acts' AND c.chapter_number = 11 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

